INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$AI-assisted editing$q$, $q$Users can describe desired changes in natural language and have the AI generate or adjust sections, copy, and layout.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Startup-focused templates$q$, $q$Prebuilt, responsive templates designed specifically for SaaS products, apps, directories, and personal founder sites.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Built-in blogging$q$, $q$An integrated blog engine for publishing content aimed at organic search traffic and audience growth.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Stripe payments$q$, $q$Direct Stripe integration lets founders sell subscriptions or products without connecting a separate checkout provider.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Custom code support$q$, $q$Ability to inject custom HTML, CSS, and JavaScript for functionality beyond the visual editor's built-in blocks.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Free SSL and CDN$q$, $q$Every published site, including free-tier sites, gets HTTPS encryption and global content delivery at no extra cost.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Custom domains$q$, $q$Connect a personal or company domain to any published site on paid plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$HTML export$q$, $q$Paid plans allow exporting a site's HTML for self-hosting outside of Unicorn Platform.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Very fast to launch a site, with many users reporting a working page within hours$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Responsive customer support directly from the small founding team$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Templates look modern and polished out of the box with minimal tweaking needed$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Affordable entry pricing compared to larger website builders like Webflow$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Built-in Stripe integration simplifies monetizing a landing page early$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Limited deep customization compared to full design tools like Webflow or Framer$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Free plan cannot publish a live website, only build and preview$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Smaller template and integration library than larger no-code competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Advanced font, spacing, and style controls are more limited than dedicated design platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Small team size means feature development can be slower than venture-backed competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$What is Unicorn Platform used for$q$, $q$It is used to build and launch marketing websites, landing pages, and blogs for SaaS products, apps, and startups without writing code.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Is Unicorn Platform free$q$, $q$There is a free Lurker plan for building and previewing a site, but publishing a live website requires a paid plan starting around 9 dollars a month billed yearly.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Who owns Unicorn Platform$q$, $q$It was founded by Alexander Isora in 2018 and acquired in 2022 by Mars, the company behind the MarsX no-code ecosystem.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Does Unicorn Platform support custom domains$q$, $q$Yes, custom domain connection is included on all paid plans along with free SSL and CDN.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Can I accept payments on a Unicorn Platform site$q$, $q$Yes, the platform integrates directly with Stripe for subscriptions and one-time payments.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Does Unicorn Platform have a blog feature$q$, $q$Yes, it includes a built-in blogging tool intended to help with content marketing and search visibility.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Can I export my website from Unicorn Platform$q$, $q$Paid plans support HTML export so a site can be self-hosted elsewhere.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$How does Unicorn Platform compare to Webflow$q$, $q$Unicorn Platform is simpler and cheaper but offers less design flexibility than Webflow, making it better suited to quick startup landing pages than complex custom sites.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$SaaS landing pages$q$, $q$Founders use Unicorn Platform to launch a marketing site for a new SaaS product before or shortly after a public beta.$q$, $q$SaaS founders and indie hackers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Startup blogs for SEO$q$, $q$Teams publish content through the built-in blog to attract organic search traffic to their product.$q$, $q$Startup marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$MVP validation pages$q$, $q$Solo builders spin up a simple site with Stripe payments to validate demand for an idea before building the full product.$q$, $q$Solo entrepreneurs and non-technical founders$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Lurker$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Build and preview sites","Up to 10 pages","Up to 10 blog posts","1 collaborator","No live publishing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Maker$q$, $q$$9/month (yearly) or $14/month (monthly)$q$, $q$monthly or yearly$q$, NULL, $q$["1 published website","Unlimited pages","Up to 10 blog posts","Custom domain"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Startup$q$, $q$$29/month (yearly) or $49/month (monthly)$q$, $q$monthly or yearly$q$, NULL, $q$["More published websites","Unlimited pages and blog posts","Form integrations"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Business$q$, $q$$49/month (yearly) or $69/month (monthly)$q$, $q$monthly or yearly$q$, NULL, $q$["Unlimited collaborators","Unlimited pages and blog posts","Branding removal"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Freelancer$q$, $q$$79/month (yearly) or $99/month (monthly)$q$, $q$monthly or yearly$q$, NULL, $q$["Higher published site limit","Client-friendly features","Unlimited collaborators"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Agency$q$, $q$$139/month (yearly) or $179/month (monthly)$q$, $q$monthly or yearly$q$, NULL, $q$["Higher published site limit for agencies","Unlimited collaborators"]$q$::jsonb, 5);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$Major$q$, $q$$250/month (yearly) or $350/month (monthly)$q$, $q$monthly or yearly$q$, NULL, $q$["Up to 100 published websites","Highest limits across all features"]$q$::jsonb, 6);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$overview$q$, $q$What Is Unicorn Platform$q$, 2, ARRAY[$q$Unicorn Platform is a no-code website builder purpose-built for startup founders who need to get a marketing site, landing page, or SaaS homepage live in hours rather than weeks. Instead of a blank canvas, it starts users with polished, pre-designed templates tailored to common startup use cases such as SaaS products, mobile apps, directories, and personal founder pages.$q$, $q$The product was created in 2018 by solo founder Alexander Isora, who bootstrapped it from an initial 2,000 dollars and grew it into a profitable business before selling it to Mars, the company behind the MarsX no-code ecosystem, in 2022. Under Mars, Unicorn Platform continues to operate as a standalone product with its own small team.$q$, $q$Newer versions of the tool add AI-assisted editing, letting users describe changes in plain language and have the AI adjust copy, layout, or new sections automatically, reducing the manual work of block-by-block editing that earlier no-code builders required.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core functionality includes a visual drag-and-drop editor, a library of startup-focused templates, a built-in blogging system for content marketing and SEO, and one-click custom domain connection with free SSL and CDN on every plan.$q$, $q$For monetization, Unicorn Platform integrates directly with Stripe so founders can sell subscriptions or one-time products from their site without external checkout tools. It also supports custom HTML, CSS, and JavaScript injection for teams that need functionality beyond the built-in blocks.$q$, $q$Collaboration and export options include multi-user site editing on higher plans, HTML export for self-hosting, form integrations, reCAPTCHA spam protection, and connections to tools like Zapier and Mailchimp.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Unicorn Platform uses a freemium model with a free Lurker tier for building and previewing sites, plus six paid tiers -- Maker, Startup, Business, Freelancer, Agency, and Major -- priced from roughly 9 to 250 dollars per month when billed annually, with monthly billing costing more per tier.$q$, $q$Paid plans progressively unlock more published websites (up to 100 on the Major plan), unlimited pages and blog posts, unlimited team collaborators on Business and above, and branding removal. All plans, including the free tier, include SSL, CDN, and custom code support, and every paid plan comes with a 30-day money-back guarantee.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('745e7d51-96b5-4e49-8391-846941129c95', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$Bidirectional synchronization$q$, $q$Detects and propagates changes made independently on both replicas, rather than mirroring in only one direction.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$Conflict detection$q$, $q$Flags files that changed on both sides since the last sync so the user can resolve the conflict manually.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$Efficient transfers$q$, $q$Uses an rsync-like algorithm to send only the changed portions of large files, saving bandwidth.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$Cross-platform support$q$, $q$Runs on Linux, macOS, Windows, and other Unix-like operating systems.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$Secure network sync$q$, $q$Can synchronize over a direct socket connection or an encrypted SSH tunnel.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$Failure resilience$q$, $q$Keeps both replicas in a stable, recoverable state even if a sync is interrupted mid-transfer.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$Command-line and GUI modes$q$, $q$Offers a scriptable CLI plus an optional GTK-based graphical interface for interactive conflict resolution.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$Cross-version compatibility$q$, $q$Since version 2.52, differing Unison builds can synchronize with each other instead of requiring identical versions.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$Completely free and open source with no usage limits or paid tiers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$True two-way synchronization rather than one-directional mirroring$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$Works well over slow or unreliable network connections$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$Encrypted synchronization over SSH for secure transfers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$Long track record of active development and stability spanning more than two decades$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$Command-line-first design has a steeper learning curve than modern consumer sync apps$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$Not a continuous background sync service like Syncthing; runs are user-initiated$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$GUI is more basic than commercial cloud-sync applications$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$No built-in cloud storage or hosted service; users must provide their own destination machines$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$What is Unison used for$q$, $q$It is used to keep two copies of a folder in sync across two computers, propagating changes made on either side and flagging genuine conflicts.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$Is Unison free$q$, $q$Yes, it is free and open-source software distributed under the GNU General Public License version 3.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$Who created Unison$q$, $q$It was created by Benjamin C. Pierce at the University of Pennsylvania, with later development by Trevor Jim, Jerome Vouillon, and other contributors.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$Does Unison sync continuously in the background$q$, $q$No, Unison is typically run on demand or via a scheduled task rather than continuously watching for changes like Syncthing.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$What operating systems does Unison support$q$, $q$Unison runs on Linux, macOS, Windows, and other Unix-like systems.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$Can Unison sync over the internet securely$q$, $q$Yes, it supports synchronization over an encrypted SSH tunnel in addition to direct socket connections.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$How is Unison different from rsync$q$, $q$Rsync mirrors files in one direction, while Unison performs full two-way synchronization and detects conflicting changes on both replicas.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$Do both machines need the same Unison version$q$, $q$Since version 2.52, different Unison versions can interoperate, though matching versions is still recommended for best compatibility.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$Keeping a laptop and desktop in sync$q$, $q$Developers and researchers use Unison to keep project files consistent between a laptop and a desktop machine without a cloud service.$q$, $q$Developers and technical users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$Syncing between a local machine and a remote server$q$, $q$Sysadmins use Unison over SSH to keep files synchronized between a workstation and a remote server.$q$, $q$System administrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$Offline-capable synchronization$q$, $q$Users who work disconnected from the network periodically reconnect and run Unison to reconcile changes made while offline.$q$, $q$Users with intermittent connectivity$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$Open Source$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Full source code under GPLv3","No usage limits","Community support via GitHub","Available on Linux, macOS, and Windows"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$overview$q$, $q$What Is Unison$q$, 2, ARRAY[$q$Unison is a free, open-source file-synchronization tool originally developed as a research project by Benjamin C. Pierce at the University of Pennsylvania. It lets two replicas of a folder tree, located on different machines or different disks, be edited independently and then brought back into agreement by propagating changes in both directions.$q$, $q$Unlike a simple mirroring or backup tool, Unison performs true bidirectional synchronization. It tracks the state of each replica between runs, so it can tell which side changed a given file since the last sync, propagate non-conflicting updates automatically, and clearly flag any file that was modified on both sides so the user can decide how to resolve it.$q$, $q$The tool runs on Linux, macOS, Windows, and other Unix-like systems, and is distributed as free software under the GNU General Public License version 3, with full source code hosted on GitHub.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Unison uses an rsync-style compression algorithm to transfer only the changed portions of large files, which keeps synchronization fast even over slow or metered connections. Transfers can run over a direct socket or through an encrypted SSH tunnel for security on untrusted networks.$q$, $q$It is resilient to interruptions: if a synchronization run is stopped partway through, by a network failure or otherwise, Unison leaves both replicas in a well-defined, recoverable state rather than a corrupted one. As of version 2.52, different builds of Unison can synchronize with each other, removing the earlier requirement that both machines run identical versions compiled against matching OCaml libraries.$q$, $q$Users can operate Unison purely from the command line, which makes it easy to script and schedule, or use an optional GTK-based graphical interface on Linux and Windows for interactively reviewing and resolving conflicts.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Unison is entirely free and open source. There are no paid tiers, subscriptions, or commercial editions -- anyone can download, use, modify, and redistribute it under the terms of the GNU General Public License version 3.$q$, $q$Because it is self-hosted between the machines the user controls, there are no server or hosting fees inherent to the tool itself; users only pay for whatever infrastructure they choose to run Unison on.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0531938d-75d2-445c-8d15-96c3a265f3c0', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2af93f8f-0570-4f36-b4b2-40e5917e9e2a', $q$Embeddable email builder$q$, $q$A drag-and-drop editor for designing responsive marketing and transactional emails inside a host product.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2af93f8f-0570-4f36-b4b2-40e5917e9e2a', $q$Landing page and popup builders$q$, $q$Additional embeddable editors for building landing pages and on-site popups using the same block system as the email builder.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2af93f8f-0570-4f36-b4b2-40e5917e9e2a', $q$Document builder$q$, $q$A builder for creating branded documents that export to PDF or other formats.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2af93f8f-0570-4f36-b4b2-40e5917e9e2a', $q$AI content tools$q$, $q$AI-assisted generation, rewriting, translation, and personalization of copy and layout sections.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2af93f8f-0570-4f36-b4b2-40e5917e9e2a', $q$Framework components$q$, $q$Prebuilt React, Angular, and Vue components that render Unlayer content to email, web, or PDF output.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2af93f8f-0570-4f36-b4b2-40e5917e9e2a', $q$White-labeling$q$, $q$Paid plans let host companies present the editor under their own branding rather than Unlayer's.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2af93f8f-0570-4f36-b4b2-40e5917e9e2a', $q$REST API, SDKs, and CLI$q$, $q$Developer tools for integrating and automating the builders within a larger product.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2af93f8f-0570-4f36-b4b2-40e5917e9e2a', $q$Multiple export formats$q$, $q$Content can be exported as HTML, PDF, images, plain text, or ZIP archives.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2af93f8f-0570-4f36-b4b2-40e5917e9e2a', $q$Deep API, SDK, and framework component support for developer-led integration$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2af93f8f-0570-4f36-b4b2-40e5917e9e2a', $q$Single JSON schema shared across email, page, popup, and document builders$q$, 1);
