-- Enrichment marathon batch: Unicorn Platform, Unison, Unlayer, Unleash, UnrealIRCd, UpCloud, Upstash, Uptime Kuma

-- ── Unicorn Platform ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Unicorn Platform is an AI-assisted no-code website builder that lets founders launch SaaS, startup, and landing page sites using prebuilt templates, a built-in blog, and Stripe payments.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $9/month billed yearly)$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Tbilisi, Georgia$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Unicorn Platform Review: AI No-Code Website Builder$q$, seo_title),
  seo_meta_description = COALESCE($q$Unicorn Platform is a no-code AI website builder for SaaS founders and startups, with templates, blogging, and Stripe payments starting free.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Unicorn Platform is a no-code, AI-assisted website builder aimed at founders, indie hackers, and startups who need to launch a SaaS, app, directory, or landing page site quickly without hiring a designer or developer. It was created in 2018 by Alexander Isora, a bootstrapped solo founder based in Tbilisi, Georgia, who built the product after a previous startup failed and grew it to roughly 16,000 dollars in monthly recurring revenue and about 500 customers by 2023. In 2022 Isora sold Unicorn Platform to Mars, the parent company behind the no-code MarsX ecosystem, for a deal combining 400,000 dollars in cash and 400,000 dollars in Mars equity, a total valuation of about 800,000 dollars. The product lets users build responsive multi-page sites from templates, edit content and layout visually, add custom HTML, CSS, and JavaScript, publish a blog for content marketing and SEO, and accept payments through Stripe integration, with newer AI features that can generate or edit pages from natural-language prompts. Unicorn Platform reports more than 104,000 websites built and over 100,000 founders served, with recognition from Product Hunt and positive ratings on G2 and Trustpilot. Pricing runs on a freemium model: a free Lurker plan for building drafts, then seven paid tiers (Maker, Startup, Business, Freelancer, Agency, Major) ranging from about 9 to 250 dollars per month on annual billing, scaling published site limits, blog posts, and collaborator seats. It competes with tools like Carrd, Webflow, Unbounce, and Framer, positioning itself as faster and cheaper for simple SaaS and startup marketing sites, though it offers less design flexibility and fewer advanced customization options than full-featured website builders.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '745e7d51-96b5-4e49-8391-846941129c95';

