-- ── Unison ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Unison is a free, open-source, cross-platform file-synchronization tool that keeps two replicas of a folder in sync across hosts, handling changes on both sides and flagging conflicts for manual resolution.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(1998, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Philadelphia, Pennsylvania, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Unison File Synchronizer: Free Open-Source Sync Tool$q$, seo_title),
  seo_meta_description = COALESCE($q$Unison is a free, open-source bidirectional file-synchronization tool for Linux, macOS, and Windows created by Benjamin Pierce at the University of Pennsylvania.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Unison is a free and open-source file-synchronization tool that allows two replicas of a collection of files and directories, stored on different hosts or on different drives of the same host, to be modified separately and then reconciled by propagating changes in both directions. It originated in the mid-to-late 1990s as a research project by Benjamin C. Pierce at the University of Pennsylvania, with an early formal specification of the synchronization algorithm published by Sundar Balasubramaniam and Pierce in 1998. The current implementation was designed and built by Trevor Jim, Benjamin Pierce, and Jerome Vouillon, with contributions from Alan Schmitt, Malo Denielou, Zhe Yang, Sylvain Gommier, and Matthieu Goulay. Unison is written in OCaml, distributed under the GNU General Public License version 3, and its source code and issue tracker are hosted on GitHub. It runs on Linux, macOS, Windows, and other Unix variants, and unlike simple mirroring tools such as rsync, it performs true two-way synchronization: it detects updates on both replicas, propagates non-conflicting changes automatically, and surfaces genuine conflicts for the user to resolve by hand. It transfers only the changed portions of large files using an rsync-like compression protocol, can run over a direct socket connection or a secure encrypted SSH tunnel, tolerates unreliable networks and interrupted transfers without corrupting replica state, and offers both a command-line interface and an optional GTK-based graphical interface on Linux and Windows. As of late 2025 the project remains actively maintained, with recent releases such as version 2.53.8, and cross-version compatibility improvements in version 2.52 that let different Unison releases talk to each other, removing the old requirement that both machines run identical builds. Unison is commonly compared to continuous, peer-to-peer sync tools like Syncthing; it differs by being a deliberately user-initiated, on-demand synchronizer rather than an always-on background service, which makes it popular among developers and Unix power users who want precise, scriptable control over when synchronization happens.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0531938d-75d2-445c-8d15-96c3a265f3c0';

