-- ── Unlayer ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Unlayer is an embeddable drag-and-drop editor for emails, landing pages, popups, and documents that SaaS companies integrate into their own products via API and SDKs.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $250/month)$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Unlayer Review: Embeddable Email and Page Design Editor$q$, seo_title),
  seo_meta_description = COALESCE($q$Unlayer is an embeddable drag-and-drop editor for emails, landing pages, and documents, built for SaaS platforms to white-label via API. Plans from free.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Unlayer is a developer-focused platform that provides embeddable, white-label drag-and-drop design editors -- for email, landing pages, popups, and documents -- that other software companies integrate directly into their own products rather than building design tools in-house. The company traces its origins to an internal tool built in 2015 and launched publicly around 2016 to 2017, later going through Y Combinator's Winter 2022 batch; it is headquartered in San Francisco, California, and employs roughly 11 to 50 people as a fully remote team. Unlayer reports powering more than 1,000 SaaS platforms, CRMs, and marketing tools, with customers including Mastercard, Bank of America, Fidelity, and Twilio, and around 5 million dollars in annual recurring revenue as of 2024, built without significant outside venture funding beyond a small early round. The product exposes a unified JSON-based content schema across its four editors, along with AI-assisted tools for generating sections, rewriting copy, translating content, and personalizing text, plus React, Angular, and Vue components, a REST API, SDKs, and a CLI for integration. Content can be exported to HTML, PDF, images, plain text, or ZIP files, and the platform is SOC 2 Type II certified with a 99.9 percent uptime SLA. Pricing runs on a freemium, usage-based model: a permanently free plan with core builders, then Launch, Scale, and Optimize plans priced from roughly 250 to 2,000 dollars per month with escalating bandwidth, white-labeling, team collaboration, and customization features, plus custom Enterprise contracts. Unlayer competes with embeddable email-builder rivals such as Beefree, Stripo, Chamaileon, and Topol, differentiating itself on developer flexibility, deep API and SDK support, and enterprise-grade security for teams that want to white-label a design tool inside their own product rather than send users to a standalone editor.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2af93f8f-0570-4f36-b4b2-40e5917e9e2a';

