-- ── Unleash ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Unleash is an open-source feature flag and feature management platform that lets engineering teams decouple deployments from releases through gradual rollouts, kill switches, and A/B testing.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted open source); paid plans from $75/seat/month$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Oslo, Norway$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Unleash Review: Open-Source Feature Flag Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Unleash is an open-source feature management platform for gradual rollouts, kill switches, and A/B testing. Free to self-host; paid plans from $75/seat.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Unleash is a feature flag and feature management platform that lets engineering teams separate code deployment from feature release, controlling rollouts through targeting rules, gradual percentage rollouts, kill switches, and A/B testing without redeploying code. The open-source project was started on GitHub in early 2015 by Ivar Osthus, and he and his brother Egil Osthus formally incorporated the company, legally named Bricks Software AS and trading as Unleash, in Oslo, Norway in 2019. Unleash has raised a total of roughly 51.5 million dollars, including a 14 million dollar Series A in March 2022 led by Spark Capital with Frontline Ventures, firstminute capital, Alliance Venture, and Arkwright X, followed by a 35 million dollar Series B in March 2026 led by One Peak Partners with existing investors Spark Capital, Frontline Ventures, and Firstminute Capital participating. The company employs roughly 11 to 50 people and is headquartered in Oslo with customers including Visa, Wayfair, Prudential, Lloyds Banking Group, Samsung, and Lenovo. The core Unleash server remains free and open source under an Apache 2.0-style license and can be fully self-hosted, while the company sells hosted Unleash Cloud and enterprise plans on top. The platform provides more than 25 official client and server SDKs across major programming languages, runtime flag evaluation at the edge with low latency, role-based access control, single sign-on via SAML and OpenID Connect, change-request approval workflows, audit logs, SOC 2 Type II and GDPR compliance, and integrations with Slack, Microsoft Teams, Datadog, and Jira. Paid plans begin at 75 dollars per seat per month for a pay-as-you-go tier with unlimited flags, projects, and environments, while Enterprise pricing is custom and adds unlimited API traffic, premium support, a dedicated customer success manager, and a 99.99 percent uptime commitment. Unleash competes with LaunchDarkly, Split, and Flagsmith, positioning itself as the leading open-source alternative for teams that want self-hosting flexibility or data residency control alongside enterprise-grade governance.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '7796a03d-4b99-4591-a6d0-97a6d4b4c39b';

