-- ── UnrealIRCd ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$UnrealIRCd is a free, open-source Internet Relay Chat server for Linux, macOS, and Windows, known for its modular design, security tooling, and status as one of the most widely deployed IRC daemons.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(1999, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$UnrealIRCd: Free Open-Source IRC Server Software$q$, seo_title),
  seo_meta_description = COALESCE($q$UnrealIRCd is a free, open-source IRC server for Linux, macOS, and Windows with SSL/TLS, spam filtering, and a JSON-RPC API. Serving networks since 1999.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$UnrealIRCd is a free and open-source Internet Relay Chat (IRC) server, or ircd, used to run real-time text chat networks. Development began around May 1999, originally based on DALnet's DreamForge ircd codebase, with the first version-controlled commit recorded in February 2000. Over more than two decades of continuous development through major version series 3.x, 4.x, 5.x, and 6.x, the project reached its 25th anniversary in 2024 and, as of mid-2026, is on the 6.2.x release line. It is maintained by a community of volunteer developers and distributed under the GNU General Public License, making it free to download, run, and modify. UnrealIRCd is widely cited as the single most deployed IRC server in the world, reportedly powering roughly a third or more of publicly listed IRC networks. Technically, it runs on Linux, macOS, and Windows, and emphasizes modularity through a plugin-style module system, along with full IRCv3 protocol support, SSL/TLS encryption for both client and server links, IP cloaking to protect user privacy, GeoIP-based features, anti-flood and anti-spam tooling including a built-in Spamfilter, WebSocket support so browser-based IRC clients can connect directly, and a JSON-RPC API for programmatic server administration. Because it is free, self-hosted software rather than a commercial SaaS product, there are no pricing tiers, subscriptions, or vendor lock-in; operators download the source or binaries, compile or install it on their own infrastructure, and configure it entirely themselves, with support available through community documentation, forums, and IRC channels rather than a paid support contract. UnrealIRCd competes with other open-source ircd projects such as InspIRCd, Charybdis, and ircd-hybrid, and remains a common choice for hobbyist, community, and legacy IRC networks that need a mature, actively maintained, security-focused server.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0a4646d4-397c-4756-8f0b-985b9dce7a8e';

