-- ── Upstash ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Upstash is a serverless database platform offering pay-per-request Redis, vector search, and message queuing services designed for edge and serverless application architectures.$q$, short_description),
  pricing_model = COALESCE($q$usage-based$q$, pricing_model),
  starting_price = COALESCE($q$Free tier available; Pay as you go from $0.20 per 100K commands, fixed plans from $10/month$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$Approximately 20-25 employees$q$, company_size),
  headquarters = COALESCE($q$San Jose, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Upstash Review: Serverless Redis and Vector Database$q$, seo_title),
  seo_meta_description = COALESCE($q$Upstash is a serverless Redis, vector, and messaging platform with pay-per-request pricing built for serverless and edge applications. Free tier available.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Upstash is a serverless data platform providing Redis-compatible caching, a vector database, message queuing through QStash, workflow orchestration, and search, all accessed through HTTP and REST APIs so they work natively in serverless and edge runtimes like Vercel Edge Functions and Cloudflare Workers, where traditional TCP-based Redis connections often fail or are inefficient. The company was founded in 2020 by Enes Akar, Mehmet Dogan, and Bilal Yasar, with CEO Enes Akar previously working in distributed systems at Confluent and Hazelcast; Upstash is headquartered in San Jose, California, and employs roughly 20 to 25 people as of 2026. Upstash has raised about 11.9 million dollars in funding, including a 1.9 million dollar seed round in March 2022 and a 10 million dollar Series A in February 2024, from investors including Andreessen Horowitz and Mango Capital, and reports processing over 160 billion Redis commands with an average uptime above 99.99 percent. The platform's signature feature is genuinely serverless, pay-per-request billing: a free tier includes 256 MB of storage and 500,000 monthly commands, a pay-as-you-go tier charges roughly 0.20 dollars per 100,000 commands plus storage and bandwidth fees with no idle cost, and fixed-price plans start at 10 dollars a month for 250 MB with unlimited commands up to a throughput ceiling; an Enterprise tier adds HIPAA compliance, unlimited databases and bandwidth, and dedicated support. Upstash's Redis is compatible with the standard Redis API over TCP as well as its own HTTP interface, and data is globally replicated across eight or more regions for low-latency reads. Compared to Redis Cloud, Upstash is generally the better fit for serverless and edge-first applications where idle-cost pricing and HTTP connectivity matter, while Redis Cloud tends to offer higher raw throughput, native Redis modules, and lower cost at very high, sustained request volumes; Upstash is frequently used alongside frameworks like Next.js and platforms like Vercel and Supabase for caching, rate limiting, session storage, and AI application infrastructure.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '72cd024d-3900-490c-976d-ace69724ddbb';

