-- ── Uptime Kuma ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Uptime Kuma is a free, open-source, self-hosted uptime monitoring tool with a modern dashboard for tracking websites, servers, and services with alerts across more than 90 notification channels.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$Chinese$q$, $q$German$q$, $q$French$q$, $q$Spanish$q$, $q$Japanese$q$]::text[],
  seo_title = COALESCE($q$Uptime Kuma: Free Self-Hosted Uptime Monitoring Tool$q$, seo_title),
  seo_meta_description = COALESCE($q$Uptime Kuma is a free, open-source, self-hosted uptime monitor with a modern dashboard, status pages, and alerts across 90-plus notification services.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Uptime Kuma is a free and open-source, self-hosted uptime monitoring tool created by developer Louis Lam, who goes by louislam on GitHub and is based in Hong Kong. It was first released in July 2021 as a response to the lack of modern, actively maintained, free self-hosted monitoring options, with Lam citing the discontinued statping-ng project as a direct motivation for building an alternative with a more current interface. The project is distributed under the MIT License, making it free to use, modify, and self-host without restriction, and it has grown into one of the most popular self-hosted monitoring tools on GitHub, surpassing roughly 88,000 stars and 8,000 forks as of mid-2026. Uptime Kuma is built with a Vue.js frontend and a Node.js backend, communicating over WebSockets rather than a traditional REST API for real-time dashboard updates, and it requires Node.js 20.4 or later to run outside of Docker. It supports monitoring a wide range of target types, including HTTP and HTTPS endpoints, TCP ports, HTTP keyword and JSON-query checks, WebSocket connections, ping, DNS records, push-based monitors, Steam game servers, and Docker containers, with checks configurable down to roughly 20-second intervals. When a monitored service goes down, Uptime Kuma can alert through more than 90 notification integrations, including Telegram, Discord, Slack, Gotify, Pushover, and standard SMTP email. The tool also includes public status pages with custom domain mapping, historical ping charts, TLS certificate expiration tracking, proxy support, two-factor authentication, and a multi-language interface translated by the community into dozens of languages. Because it is entirely open source and self-hosted, Uptime Kuma has no official pricing tiers; it is most commonly deployed via Docker on a home server, VPS, or NAS device, and is frequently compared to commercial SaaS competitors like UptimeRobot, Better Uptime, and Pingdom, offering similar or greater monitor-type flexibility at no cost in exchange for the user managing their own hosting and updates.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0a5a7e0d-829a-4fbf-b817-7512ee40ab96';

